mapper.select:
select * from ( select cr.*, u.name as name, approver.name as approver_name, d.dept_name, r.rank_name, row_number() over (order by cr.checkout_seq desc) rn from checkout_request cr JOIN users u ON cr.users_id = u.id LEFT JOIN users approver ON cr.approver_id = approver.id JOIN departments d ON u.dept_seq = d.dept_seq JOIN rank r ON u.rank_seq = r.rank_seq
cr.status = #{status}
) where rn between #{start} and #{end}

mapper.update:
update checkout_request set 
	status = 'APPROVED', approver_id = #{approver_id}, approved_at = sysdate 
where checkout_seq = #{checkout_seq}

update checkout_request set 
	status = 'REJECTED', approver_id = #{approver_id}, approved_at = sysdate 
where checkout_seq = #{checkout_seq}
